#!/usr/bin/env python3
"""
MoneyMath — General Image Generation Pipeline
Generates scene images using Gemini with an optional reference character image.

Usage:
  1. Set USE_REF_IMAGE = True/False depending on whether a character reference is needed
  2. If True, place your character reference image at reference/character.png
  3. Edit IMAGES below with your scene prompts
  4. Set PROJECT_NAME to your project folder name
  5. Run: python3 generate_images.py
"""

import os
import sys
import time
import base64
import json
import concurrent.futures
from pathlib import Path
from dotenv import load_dotenv

ROOT = Path(__file__).resolve().parent.parent
load_dotenv(ROOT / ".env")

from cost_tracker import log_gemini_image_cost

# ══════════════════════════════════════════════════════════
# API KEYS — Loaded from .env (more keys = faster parallel generation)
# ══════════════════════════════════════════════════════════

API_KEYS = [
    os.getenv("GEMINI_API_KEY"),
    os.getenv("GEMINI_KEY_1"),
    os.getenv("GEMINI_KEY_2"),
    os.getenv("GEMINI_KEY_3"),
    os.getenv("GEMINI_KEY_4"),
    os.getenv("GEMINI_KEY_5"),
    os.getenv("GEMINI_KEY_6"),
    os.getenv("GEMINI_KEY_7"),
    os.getenv("GEMINI_KEY_8"),
]
API_KEYS = [k for k in API_KEYS if k]
if not API_KEYS:
    print("ERROR: No GEMINI API keys found in .env")
    sys.exit(1)
print(f"Loaded {len(API_KEYS)} API keys")

# ══════════════════════════════════════════════════════════
# CONFIGURATION — Edit these for each new video
# ══════════════════════════════════════════════════════════

PROJECT_NAME = "war-dollar"  # Folder name under public/

MODEL = "gemini-3.1-flash-image-preview"

# ══════════════════════════════════════════════════════════
# CHARACTER REFERENCES — Multi-character casting system
# ══════════════════════════════════════════════════════════
# Each image's IMAGES tuple includes a ref_characters list that controls
# which reference images are sent to Gemini for that specific image.
#   "joseph"  — main male character, appears in most/all images
#   "jess"    — main female character, used when scene has a woman
#   "sola"    — girl child, used when scene has a girl
#   "brayden" — boy child, used when scene has a boy
# Use all four ONLY for explicit family scenes.

_MIME_MAP = {"png": "image/png", "jpg": "image/jpeg", "jpeg": "image/jpeg", "webp": "image/webp"}

_CHARACTER_FILES = {
    "joseph":  "reference/joseph.png",
    "jess":    "reference/jessw.png",
    "sola":    "reference/solaw.png",
    "brayden": "reference/braydenw.png",
}

_CHARACTER_LABELS = {
    "joseph":  "the main male character (Joseph)",
    "jess":    "the main female character (Jess)",
    "sola":    "the girl child (Sola)",
    "brayden": "the boy child (Brayden)",
}

REF_IMAGES = {}
for _char_name, _char_file in _CHARACTER_FILES.items():
    _char_path = ROOT / _char_file
    if _char_path.exists():
        _ext = _char_path.suffix.lower().lstrip(".")
        REF_IMAGES[_char_name] = {
            "bytes": _char_path.read_bytes(),
            "mime": _MIME_MAP.get(_ext, "image/png"),
        }
        print(f"Loaded reference: {_char_name} → {_char_path} ({len(REF_IMAGES[_char_name]['bytes']) // 1024} KB)")
    else:
        print(f"WARNING: Reference image not found: {_char_path}")

if not REF_IMAGES:
    print("WARNING: No character reference images loaded")

